"use client"

import { cn } from "@/lib/utils"
import { ChevronDown, ChevronUp, Check, Loader2 } from "lucide-react"
import { useState } from "react"

export interface AgentStatus {
    agent: string
    icon: string
    message: string
    status: "running" | "complete" | "pending"
}

interface AgentStatusDisplayProps {
    statuses: AgentStatus[]
    isCollapsible?: boolean
    theme?: "light" | "dark"
}

export function AgentStatusDisplay({ statuses, isCollapsible = true, theme = "dark" }: AgentStatusDisplayProps) {
    const [isExpanded, setIsExpanded] = useState(true)

    if (statuses.length === 0) return null

    const hasRunning = statuses.some(s => s.status === "running")
    const allComplete = statuses.every(s => s.status === "complete")

    return (
        <div className={cn(
            "rounded-lg border",
            theme === "dark" ? "bg-[#1e1f20] border-[#3c4043]" : "bg-gray-50 border-gray-200"
        )}>
            {/* Header */}
            {isCollapsible && (
                <button
                    onClick={() => setIsExpanded(!isExpanded)}
                    className={cn(
                        "w-full flex items-center justify-between px-4 py-3 text-sm font-medium",
                        theme === "dark" ? "text-[#e3e3e3] hover:bg-[#2a2b2d]" : "text-gray-900 hover:bg-gray-100",
                        "transition-colors rounded-t-lg"
                    )}
                >
                    <span className="flex items-center gap-2">
                        {hasRunning && <Loader2 className="h-4 w-4 animate-spin text-blue-500" />}
                        {allComplete && <Check className="h-4 w-4 text-green-500" />}
                        <span>
                            {hasRunning ? "Processing..." : allComplete ? "Completed" : "Planning..."}
                        </span>
                    </span>
                    {isExpanded ? (
                        <ChevronUp className="h-4 w-4" />
                    ) : (
                        <ChevronDown className="h-4 w-4" />
                    )}
                </button>
            )}

            {/* Status List */}
            {isExpanded && (
                <div className={cn(
                    "px-4 pb-3",
                    isCollapsible && "pt-0",
                    !isCollapsible && "py-3"
                )}>
                    <div className="space-y-2">
                        {statuses.map((status, index) => (
                            <div
                                key={`${status.agent}-${index}`}
                                className={cn(
                                    "flex items-center gap-3 text-sm",
                                    theme === "dark" ? "text-[#9aa0a6]" : "text-gray-600"
                                )}
                            >
                                {/* Status indicator */}
                                <div className="flex-shrink-0 w-5 h-5 flex items-center justify-center">
                                    {status.status === "running" && (
                                        <Loader2 className="h-4 w-4 animate-spin text-blue-500" />
                                    )}
                                    {status.status === "complete" && (
                                        <Check className="h-4 w-4 text-green-500" />
                                    )}
                                    {status.status === "pending" && (
                                        <div className="w-2 h-2 rounded-full bg-gray-400" />
                                    )}
                                </div>

                                {/* Icon and message */}
                                <span className="flex items-center gap-2">
                                    <span>{status.icon}</span>
                                    <span className={cn(
                                        status.status === "complete" && "line-through opacity-60"
                                    )}>
                                        {status.message}
                                    </span>
                                </span>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    )
}
